/* ------------------------------------------------------------------ */
/* Borrower ratio engine (mirrors pipeline overlay.py)                  */
/* ------------------------------------------------------------------ */

const M = 1e6; // inputs are entered in $M, converted to raw USD

const BORROWER_FIELDS = [
  ["revenue", "Revenue"],
  ["ebitda", "EBITDA (normalized)"],
  ["total_debt", "Total debt"],
  ["cash", "Cash & equivalents"],
  ["interest_expense", "Interest expense"],
  ["capex", "Capex"],
  ["cogs", "COGS"],
  ["receivables", "Receivables"],
  ["inventory", "Inventory"],
  ["payables", "Payables"],
  ["current_assets", "Current assets"],
  ["current_liabilities", "Current liabilities"],
  ["total_assets", "Total assets"],
  ["rent_expense", "Rent expense"],
];

function computeRatios(years, segMetrics) {
  // years: ascending [{fy, fields in raw USD}]; segMetrics: metric keys
  // available for the segment/bucket (drives suppression + extras).
  const out = {};
  years.forEach((y, i) => {
    const r = {};
    const has = (k) => y[k] !== null && y[k] !== undefined && !isNaN(y[k]);
    if (has("ebitda") && y.ebitda > 0) {
      if (has("total_debt")) {
        r.debt_ebitda = y.total_debt / y.ebitda;
        if (has("cash")) r.net_debt_ebitda = (y.total_debt - y.cash) / y.ebitda;
      }
      if (has("revenue") && y.revenue > 0)
        r.ebitda_margin = (y.ebitda / y.revenue) * 100;
    } else if (has("ebitda") && y.ebitda <= 0 && has("total_debt")) {
      r.debt_ebitda = NaN; // graded severe: leverage on negative EBITDA
    }
    if (has("interest_expense") && y.interest_expense > 0 && has("ebitda")) {
      r.interest_coverage = y.ebitda / y.interest_expense;
      if (has("capex"))
        r.fcc_proxy = (y.ebitda - y.capex) / y.interest_expense;
    }
    if (has("revenue") && y.revenue > 0) {
      if (has("cogs")) r.gross_margin = ((y.revenue - y.cogs) / y.revenue) * 100;
      if (has("receivables")) r.dso = (y.receivables / y.revenue) * 365;
    }
    if (has("cogs") && y.cogs > 0) {
      if (has("inventory")) r.dio = (y.inventory / y.cogs) * 365;
      if (has("payables")) r.dpo = (y.payables / y.cogs) * 365;
    }
    if ("dso" in r && "dio" in r && "dpo" in r) r.ccc = r.dso + r.dio - r.dpo;
    if (has("current_assets") && has("current_liabilities") && y.current_liabilities > 0)
      r.current_ratio = y.current_assets / y.current_liabilities;
    if (has("total_assets") && y.total_assets > 0 && has("total_debt"))
      r.debt_assets = (y.total_debt / y.total_assets) * 100;
    if (has("rent_expense") && has("ebitda") && has("total_debt")) {
      const ebitdar = y.ebitda + y.rent_expense;
      if (ebitdar > 0)
        r.rent_adj_leverage = (y.total_debt + 8 * y.rent_expense) / ebitdar;
    }
    if (has("total_debt") && i >= 2) {
      const win = years.slice(i - 2, i + 1).map((p) => p.ebitda)
        .filter((e) => e !== null && e !== undefined && !isNaN(e));
      if (win.length === 3 && win.reduce((a, b) => a + b, 0) > 0)
        r.debt_ebitda_3y = y.total_debt / (win.reduce((a, b) => a + b, 0) / 3);
    }
    const prev = i > 0 ? years[i - 1] : null;
    if (prev && prev.revenue > 0 && has("revenue") && prev.fy === y.fy - 1)
      r.rev_growth = (y.revenue / prev.revenue - 1) * 100;
    // suppression: only metrics the segment benchmark carries
    Object.keys(r).forEach((k) => { if (!segMetrics.has(k)) delete r[k]; });
    out[y.fy] = r;
  });
  return out;
}

function interpPercentile(value, d) {
  const pts = [[10, d.p10], [25, d.p25], [50, d.p50], [75, d.p75], [90, d.p90]];
  if (value <= pts[0][1]) return value < pts[0][1] ? 2 : 10;
  if (value >= pts[4][1]) return value > pts[4][1] ? 98 : 90;
  for (let i = 0; i < 4; i++) {
    const [p0, v0] = pts[i], [p1, v1] = pts[i + 1];
    if (v1 < v0) return 50; // degenerate summary
    if (value >= v0 && value <= v1)
      return v1 === v0 ? (p0 + p1) / 2 : p0 + ((p1 - p0) * (value - v0)) / (v1 - v0);
  }
  return 50;
}

function gradeValue(value, d, direction) {
  if (isNaN(value)) return "severe";
  const iqr = Math.abs(d.p75 - d.p25);
  if (direction === "higher_is_riskier") {
    if (value > d.p90 + 0.25 * iqr) return "severe";
    if (value > d.p90) return "departure";
    if (value > d.p75) return "watch";
  } else {
    if (value < d.p10 - 0.25 * iqr) return "severe";
    if (value < d.p10) return "departure";
    if (value < d.p25) return "watch";
  }
  return "in_range";
}

function framing(valuesByFy, peerMedian) {
  const fys = Object.keys(valuesByFy).map(Number).sort((a, b) => a - b);
  const latest = valuesByFy[fys[fys.length - 1]];
  if (fys.length < 2 || isNaN(latest))
    return {
      cls: "single_period",
      text: "Single-period figure: departure vs. normalization cannot be " +
        "distinguished without at least two fiscal years -- obtain history " +
        "before treating the gap as structural.",
    };
  const prior = valuesByFy[fys[0]];
  const gapNow = latest - peerMedian, gapThen = prior - peerMedian;
  const span = fys[fys.length - 1] - fys[0];
  const perYr = (Math.abs(gapNow) - Math.abs(gapThen)) / span;
  const relMove = Math.abs(gapThen) > 1e-12
    ? (Math.abs(gapNow) - Math.abs(gapThen)) / Math.abs(gapThen) : null;
  if (relMove !== null && Math.abs(relMove) < 0.1)
    return {
      cls: "persistent_departure",
      text: `Gap to peer median roughly static over FY${fys[0]}-FY${fys[fys.length - 1]} ` +
        "-- a persistent structural departure. The question is whether the " +
        "business model explains a permanently different level, not when it " +
        "will revert.",
    };
  if (Math.abs(gapNow) < Math.abs(gapThen))
    return {
      cls: "normalization",
      text: `Moving toward the peer baseline (gap closing ~${Math.abs(perYr).toPrecision(2)}/yr ` +
        `since FY${fys[0]}) -- reads as normalization toward the segment norm ` +
        "rather than new deterioration; confirm the driver is durable, not one-off.",
    };
  return {
    cls: "structural_departure",
    text: `Moving away from the peer baseline (gap widening ~${Math.abs(perYr).toPrecision(2)}/yr ` +
      `since FY${fys[0]}) -- a structural departure in motion, the pattern ` +
      "that precedes migration to criticized status; mechanism review warranted now.",
  };
}

/* ------------------------------------------------------------------ */
/* Formatting                                                           */
/* ------------------------------------------------------------------ */

function fmt(v, unit) {
  if (v === null || v === undefined) return "--";
  if (isNaN(v)) return "n/m";
  if (unit === "x") return `${v.toFixed(2)}x`;
  if (unit === "%") return `${v.toFixed(1)}%`;
  if (unit === "days") return `${Math.round(v)}d`;
  if (unit === "USD") return `$${(v / M).toFixed(1)}M`;
  return String(v);
}

const FLAG_STYLE = {
  in_range: { bg: "#dcfce7", fg: "#15803d", label: "IN RANGE" },
  watch: { bg: "#fef3c7", fg: "#b45309", label: "WATCH" },
  departure: { bg: "#ffedd5", fg: "#c2410c", label: "DEPARTURE" },
  severe: { bg: "#fee2e2", fg: "#b91c1c", label: "SEVERE" },
  no_benchmark: { bg: "#e2e8f0", fg: "#475569", label: "NO BENCHMARK" },
};

const FRAMING_LABEL = {
  stable_in_range: "Stable, in range",
  single_period: "Single period -- trajectory unknown",
  normalization: "Normalizing toward baseline",
  structural_departure: "Structural departure (widening)",
  persistent_departure: "Persistent structural departure",
};

/* ------------------------------------------------------------------ */
/* SVG: distribution strip                                              */
/* ------------------------------------------------------------------ */

function DistStrip({ adj, raw, value, direction, unit, width = 330, ghost }) {
  const h = 54, bandY = 22, bandH = 12;
  const vals = [];
  [adj, ghost ? raw : null].forEach((d) => {
    if (d) vals.push(d.p10, d.p90);
  });
  if (value !== null && value !== undefined && !isNaN(value)) vals.push(value);
  if (!vals.length) return null;
  let lo = Math.min(...vals), hi = Math.max(...vals);
  const pad = (hi - lo || Math.abs(hi) || 1) * 0.08;
  lo -= pad; hi += pad;
  const x = (v) => 12 + ((v - lo) / (hi - lo)) * (width - 24);
  const riskRight = direction === "higher_is_riskier";
  return (
    <svg width={width} height={h} style={{ display: "block" }}>
      {/* risky-direction hint */}
      <text x={riskRight ? width - 12 : 12} y={12} fontSize={9}
        fill="#94a3b8" textAnchor={riskRight ? "end" : "start"}>
        riskier {riskRight ? "→" : "←"}
      </text>
      {ghost && raw && (
        <g>
          <rect x={x(raw.p10)} y={bandY - 7} width={Math.max(1, x(raw.p90) - x(raw.p10))}
            height={4} fill="#cbd5e1" rx={2} />
          <rect x={x(raw.p25)} y={bandY - 8} width={Math.max(1, x(raw.p75) - x(raw.p25))}
            height={6} fill="#94a3b8" rx={2} />
          <text x={12} y={bandY - 10} fontSize={8.5} fill="#64748b">raw public</text>
        </g>
      )}
      {adj && (
        <g>
          <rect x={x(adj.p10)} y={bandY} width={Math.max(1, x(adj.p90) - x(adj.p10))}
            height={bandH} fill="#dbeafe" rx={3} />
          <rect x={x(adj.p25)} y={bandY} width={Math.max(1, x(adj.p75) - x(adj.p25))}
            height={bandH} fill="#93c5fd" rx={3} />
          <line x1={x(adj.p50)} x2={x(adj.p50)} y1={bandY - 2} y2={bandY + bandH + 2}
            stroke="#1d4ed8" strokeWidth={2} />
          <text x={x(adj.p50)} y={bandY + bandH + 12} fontSize={9} fill="#1d4ed8"
            textAnchor="middle">med {fmt(adj.p50, unit)}</text>
          <text x={x(adj.p10)} y={bandY + bandH + 12} fontSize={8.5} fill="#64748b"
            textAnchor="middle">{fmt(adj.p10, unit)}</text>
          <text x={x(adj.p90)} y={bandY + bandH + 12} fontSize={8.5} fill="#64748b"
            textAnchor="middle">{fmt(adj.p90, unit)}</text>
        </g>
      )}
      {value !== null && value !== undefined && !isNaN(value) && (
        <g>
          <line x1={x(value)} x2={x(value)} y1={bandY - 6} y2={bandY + bandH + 2}
            stroke="#b45309" strokeWidth={2} />
          <path d={`M ${x(value)} ${bandY - 12} l 5 6 l -5 6 l -5 -6 z`}
            fill="#d97706" stroke="#92400e" strokeWidth={0.8} />
        </g>
      )}
    </svg>
  );
}

/* ------------------------------------------------------------------ */
/* SVG: trend chart (peer median band + baseline + borrower path)       */
/* ------------------------------------------------------------------ */

function TrendChart({ trend, baseline, borrower, unit, width = 430, height = 170 }) {
  // trend: [{fy,p25,p50,p75}], baseline: {p50} | null, borrower: {fy: value}
  const mL = 46, mR = 12, mT = 14, mB = 24;
  const bFys = Object.keys(borrower || {}).map(Number);
  const fys = [...new Set([...(trend || []).map((t) => t.fy), ...bFys])].sort((a, b) => a - b);
  if (!fys.length) return <div style={{ color: "#64748b", fontSize: 12 }}>
    No trend data at this size band (see coverage gaps).</div>;
  const ys = [];
  (trend || []).forEach((t) => ys.push(t.p25, t.p50, t.p75));
  bFys.forEach((fy) => { if (!isNaN(borrower[fy])) ys.push(borrower[fy]); });
  if (baseline) ys.push(baseline.p50);
  let lo = Math.min(...ys), hi = Math.max(...ys);
  const pad = (hi - lo || Math.abs(hi) || 1) * 0.12;
  lo -= pad; hi += pad;
  const X = (fy) => fys.length === 1 ? (mL + (width - mL - mR) / 2)
    : mL + ((fy - fys[0]) / (fys[fys.length - 1] - fys[0])) * (width - mL - mR);
  const Y = (v) => mT + (1 - (v - lo) / (hi - lo)) * (height - mT - mB);
  const line = (pts) => pts.map((p, i) => `${i ? "L" : "M"} ${X(p[0])} ${Y(p[1])}`).join(" ");
  const t = trend || [];
  const band = t.length >= 2
    ? `${line(t.map((d) => [d.fy, d.p75]))} ${t.slice().reverse()
      .map((d) => `L ${X(d.fy)} ${Y(d.p25)}`).join(" ")} Z`
    : null;
  const bPts = bFys.sort((a, b) => a - b).filter((fy) => !isNaN(borrower[fy]))
    .map((fy) => [fy, borrower[fy]]);
  return (
    <svg width={width} height={height} style={{ display: "block" }}>
      {[lo + pad, (lo + hi) / 2, hi - pad].map((v, i) => (
        <g key={i}>
          <line x1={mL} x2={width - mR} y1={Y(v)} y2={Y(v)} stroke="#e2e8f0" />
          <text x={mL - 6} y={Y(v) + 3} fontSize={9} fill="#64748b"
            textAnchor="end">{fmt(v, unit)}</text>
        </g>
      ))}
      {band && <path d={band} fill="#dbeafe" opacity={0.7} />}
      {t.length >= 1 && (
        <path d={line(t.map((d) => [d.fy, d.p50]))} fill="none"
          stroke="#1d4ed8" strokeWidth={2} />
      )}
      {baseline && (
        <g>
          <line x1={mL} x2={width - mR} y1={Y(baseline.p50)} y2={Y(baseline.p50)}
            stroke="#0f766e" strokeWidth={1.5} strokeDasharray="5 4" />
          <text x={width - mR} y={Y(baseline.p50) - 4} fontSize={9} fill="#0f766e"
            textAnchor="end">pre-2020 baseline</text>
        </g>
      )}
      {bPts.length > 0 && (
        <g>
          {bPts.length > 1 && (
            <path d={line(bPts)} fill="none" stroke="#d97706" strokeWidth={2} />
          )}
          {bPts.map(([fy, v]) => (
            <circle key={fy} cx={X(fy)} cy={Y(v)} r={4} fill="#d97706"
              stroke="#92400e" strokeWidth={1} />
          ))}
        </g>
      )}
      {fys.map((fy) => (
        <text key={fy} x={X(fy)} y={height - 8} fontSize={9.5} fill="#475569"
          textAnchor="middle">FY{fy}</text>
      ))}
      <text x={mL} y={mT - 3} fontSize={9} fill="#1d4ed8">peer median (p25-p75 band)</text>
    </svg>
  );
}

/* ------------------------------------------------------------------ */
/* Memo generation                                                      */
/* ------------------------------------------------------------------ */

function buildMemo({ name, segKey, bucketKey, view, years, ratiosByFy, results,
  bucketData, segData, meta, adjustmentParams, validation }) {
  const fys = Object.keys(ratiosByFy).map(Number).sort((a, b) => a - b);
  const fy = fys[fys.length - 1];
  const L = [];
  const isSynthetic = meta.data_source !== "EDGAR_LIVE";
  L.push(`# Benchmark review memo -- ${name || "[unnamed borrower]"}`);
  L.push("");
  L.push(`**Segment:** ${segData.label} | **Size band:** ${bucketData.label} | ` +
    `**Latest FY:** FY${fy} | **View used for flags:** ${view === "adjusted"
      ? "private-MM adjusted" : "raw public"} | **Prepared:** ${new Date().toISOString().slice(0, 10)}`);
  L.push("");
  L.push(`**Benchmark data:** ${meta.pipeline}, snapshot ${meta.version} ` +
    `(generated ${meta.generated_utc}), source: ${meta.data_source}.`);
  if (isSynthetic) {
    L.push("");
    L.push("> **DATA CAVEAT:** " + (meta.source_notes && meta.source_notes[0]
      ? meta.source_notes[0]
      : "Snapshot built from synthetic demonstration data; refresh against " +
      "live EDGAR before relying on the levels."));
  }
  L.push("");
  L.push("## Position vs. peer distributions");
  L.push("");
  L.push("| Metric | Borrower | Peer median (adj.) | Percentile (adj.) | Flag | Basis |");
  L.push("|---|---|---|---|---|---|");
  const order = Object.keys(results);
  order.forEach((mk) => {
    const r = results[mk];
    const med = r.adjusted_dist ? fmt(r.adjusted_dist.p50, r.unit) : "--";
    const pct = r.percentile != null ? `p${Math.round(r.percentile)}` : "--";
    L.push(`| ${r.label} | ${fmt(r.value, r.unit)} | ${med} | ${pct} | ` +
      `${(FLAG_STYLE[r.flag] || {}).label || r.flag} | ${r.basis.split(".")[0]}. |`);
  });
  L.push("");
  L.push("All borrower figures are lender-provided, fiscal-year basis, USD. " +
    "Peer distributions are fiscal-year company observations; every cell's " +
    "full basis and per-datapoint provenance route is recorded in the " +
    "benchmark snapshot and pipeline panel.");
  const flagged = order.filter((mk) => !["in_range", "no_benchmark"].includes(results[mk].flag));
  L.push("");
  L.push("## Findings (departure vs. normalization)");
  L.push("");
  if (!flagged.length) {
    L.push("No metric graded beyond the adjusted interquartile range. " +
      "Within-range positioning is reported without further rationale.");
  }
  flagged.forEach((mk) => {
    const r = results[mk];
    L.push(`### ${r.label}: ${fmt(r.value, r.unit)} -- ${(FLAG_STYLE[r.flag] || {}).label}`);
    L.push("");
    const histVals = fys.filter((f) => mk in ratiosByFy[f])
      .map((f) => `FY${f} ${fmt(ratiosByFy[f][mk], r.unit)}`).join(", ");
    L.push(`Path: ${histVals}. Adjusted peer band (p25-p75): ` +
      `${r.adjusted_dist ? `${fmt(r.adjusted_dist.p25, r.unit)}-${fmt(r.adjusted_dist.p75, r.unit)}` : "--"}; ` +
      `raw public band: ${r.raw_dist ? `${fmt(r.raw_dist.p25, r.unit)}-${fmt(r.raw_dist.p75, r.unit)}` : "--"}.`);
    L.push("");
    L.push(`**Trajectory:** ${FRAMING_LABEL[r.framing.cls] || r.framing.cls}. ${r.framing.text}`);
    L.push("");
    L.push(`**Mechanism:** ${r.mechanism}`);
    L.push("");
    L.push(`**Basis:** ${r.basis}`);
    if (r.baseline_pre2020)
      L.push(`**Historical anchor:** pre-2020 peer median ${fmt(r.baseline_pre2020.p50, r.unit)} ` +
        `(raw, pooled FY2015-2019) vs. current ${r.raw_dist ? fmt(r.raw_dist.p50, r.unit) : "--"}.`);
    L.push(`**Adjustment applied:** ${r.adjustment_note || "none"}`);
    if (r.coverage_gaps && r.coverage_gaps.length)
      L.push(`**Coverage gaps on this metric:** ${r.coverage_gaps.join("; ")}`);
    L.push("");
  });
  L.push("## Coverage gaps");
  L.push("");
  const gaps = [
    ...(bucketData.coverage_gaps || []),
    ...order.flatMap((mk) => (results[mk].coverage_gaps || [])
      .map((g) => `${results[mk].label}: ${g}`)),
  ];
  const inputGaps = (segData.primaryMissing || []);
  inputGaps.forEach((g) => gaps.push(g));
  if (gaps.length) {
    [...new Set(gaps)].forEach((g) => L.push(`- ${g}`));
  } else {
    L.push("- None noted at this segment/size band.");
  }
  L.push("");
  L.push("## Methodology appendix");
  L.push("");
  L.push(`**Peer set:** ${segData.peer_definition}`);
  L.push("");
  L.push("**Normalization rules applied to the peer set:**");
  (segData.normalization_rules || []).forEach((r) => L.push(`- ${r}`));
  L.push("");
  L.push(`**Cyclicality treatment:** ${segData.cyclicality_treatment}`);
  L.push("");
  const ap = adjustmentParams[bucketKey];
  if (ap) {
    L.push(`**Size-distortion / survivorship adjustment (this band):** ` +
      `dispersion widened x${ap.dispersion_widening}; margin medians haircut ` +
      `${ap.margin_haircut_pp}pp; coverage medians shifted ${ap.coverage_shift_x}x; ` +
      `risky tail extended ${Math.round(ap.survivorship_tail_extension * 100)}% of IQR. ` +
      `Rationale: ${ap.rationale} These parameters are judgment calibration ` +
      `and are tunable; raw and adjusted views are shown side by side in the ` +
      `workbench and above.`);
  }
  L.push("");
  if (validation) {
    const pc = (x) => (x == null ? "n/a" : `${Math.round(x * 100)}%`);
    L.push(`**Flag-rule validation (public-proxy backtest):** hit rate ` +
      `${pc(validation.hit_rate)}, capture rate ${pc(validation.capture_rate)}, ` +
      `median lead time ${validation.median_lead_time_years} yr over ` +
      `FY${validation.flag_fy_range[0]}-FY${validation.flag_fy_range[1]} ` +
      `(vs. base deterioration rate ${pc(validation.base_deterioration_rate)}; ` +
      `Altman Z' reference hit rate ${pc(validation.altman_z_reference.hit_rate)}). ` +
      `Caveats: ${validation.caveats[0]}`);
  }
  L.push("");
  L.push(`**Refresh:** ${meta.refresh}`);
  L.push("");
  L.push("*Every quantitative figure above carries its basis label; peer " +
    "figures trace to the versioned snapshot and per-datapoint provenance " +
    "(CIK, accession, tag, form, filed date) in the pipeline panel. " +
    "Prepared with the Commercial Credit Benchmark Workbench.*");
  return L.join("\n");
}

